// Tambah.js - Redesigned
import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { motion } from 'framer-motion';
import ProjectForm from '../components/ProjectForm';

const API = '';

export default function Tambah() {
  const navigate = useNavigate();
  const [kategoriList, setKategoriList] = useState([]);
  const [teknologiList, setTeknologiList] = useState([]);
  const [loading, setLoading] = useState(false);

  const [form, setForm] = useState({
    nama_project: '',
    kategori_id: '',
    deskripsi: '',
    github: '',
    demo: '',
  });
  const [gambarFile, setGambarFile] = useState(null);
  const [selectedTech, setSelectedTech] = useState([]);

  useEffect(() => {
    fetch(`${API}/api/kategori`).then(r => r.json()).then(setKategoriList).catch(console.error);
    fetch(`${API}/api/teknologi`).then(r => r.json()).then(setTeknologiList).catch(console.error);
  }, []);

  const handleChange = (e) => {
    setForm(prev => ({ ...prev, [e.target.name]: e.target.value }));
  };

  const handleTechChange = (id) => {
    setSelectedTech(prev =>
      prev.includes(id) ? prev.filter(t => t !== id) : [...prev, id]
    );
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);

    const data = new FormData();
    data.append('nama_project', form.nama_project);
    data.append('kategori_id', form.kategori_id);
    data.append('deskripsi', form.deskripsi);
    data.append('github', form.github);
    data.append('demo', form.demo);
    if (gambarFile) data.append('gambar', gambarFile);
    selectedTech.forEach(tid => data.append('teknologi[]', tid));

    try {
      const res = await fetch(`${API}/api/projects`, { method: 'POST', body: data });
      const result = await res.json();
      if (result.success) navigate('/admin?status=tambah');
      else alert('Failed to save project');
    } catch (err) {
      alert('Error: ' + err.message);
    } finally {
      setLoading(false);
    }
  };

  return (
    <ProjectForm title="Add New Project" icon="fa-plus-circle" onSubmit={handleSubmit} loading={loading}>
      <div className="mb-3">
        <label className="form-label">Project Name</label>
        <input type="text" className="form-control" name="nama_project" value={form.nama_project} onChange={handleChange} required placeholder="Enter project name" />
      </div>

      <div className="mb-3">
        <label className="form-label">Category</label>
        <select name="kategori_id" className="form-select" value={form.kategori_id} onChange={handleChange} required>
          <option value="">Select Category</option>
          {kategoriList.map(k => (
            <option key={k.id} value={k.id}>{k.kategori}</option>
          ))}
        </select>
      </div>

      <div className="mb-3">
        <label className="form-label">Description</label>
        <textarea className="form-control" name="deskripsi" rows="4" value={form.deskripsi} onChange={handleChange} required placeholder="Describe your project"></textarea>
      </div>

      <div className="mb-3">
        <label className="form-label">Project Image</label>
        <input type="file" className="form-control" accept="image/*" onChange={e => setGambarFile(e.target.files[0])} />
        <small className="text-light">Format: JPG, PNG, GIF (Max 2MB)</small>
      </div>

      <div className="mb-3">
        <label className="form-label">GitHub Link</label>
        <input type="url" className="form-control" name="github" value={form.github} onChange={handleChange} placeholder="https://github.com/..." />
      </div>

      <div className="mb-3">
        <label className="form-label">Demo Link</label>
        <input type="url" className="form-control" name="demo" value={form.demo} onChange={handleChange} placeholder="https://..." />
      </div>

      <div className="mb-4">
        <label className="form-label d-block">Technologies Used</label>
        <div className="row g-2">
          {teknologiList.map(tech => (
            <div className="col-md-4" key={tech.id}>
              <div className="form-check">
                <input
                  className="form-check-input"
                  type="checkbox"
                  id={`tech_${tech.id}`}
                  checked={selectedTech.includes(tech.id)}
                  onChange={() => handleTechChange(tech.id)}
                />
                <label className="form-check-label" htmlFor={`tech_${tech.id}`}>
                  {tech.nama_teknologi}
                </label>
              </div>
            </div>
          ))}
        </div>
      </div>
    </ProjectForm>
  );
}
